<!DOCTYPE html>\n<html lang="en">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>Dashboard</title>\n    <link rel="stylesheet" href="https://stackpath.bootstrapcdn.com/bootstrap/4.5.2/css/bootstrap.min.css">\n</head>\n<body>\n    <div class="container mt-5">\n        <h1>Dashboard</h1>\n        <div class="row">\n            <div class="col-md-3">\n                <div class="card text-white bg-primary mb-3">\n                    <div class="card-header">Semi-Finished Stock</div>\n                    <div class="card-body">\n                        <h5 class="card-title">100</h5>\n                        <p class="card-text">Items in stock</p>\n                        <button class="btn btn-light">Quick Action</button>\n                    </div>\n                </div>\n            </div>\n            <div class="col-md-3">\n                <div class="card text-white bg-success mb-3">\n                    <div class="card-header">Finished Goods Stock</div>\n                    <div class="card-body">\n                        <h5 class="card-title">200</h5>\n                        <p class="card-text">Items in stock</p>\n                        <button class="btn btn-light">Quick Action</button>\n                    </div>\n                </div>\n            </div>\n            <div class="col-md-3">\n                <div class="card text-white bg-warning mb-3">\n                    <div class="card-header">Packing Material Stock</div>\n                    <div class="card-body">\n                        <h5 class="card-title">50</h5>\n                        <p class="card-text">Items in stock</p>\n                        <button class="btn btn-light">Quick Action</button>\n                    </div>\n                </div>\n            </div>\n            <div class="col-md-3">\n                <div class="card text-white bg-info mb-3">\n                    <div class="card-header">Total Products Count</div>\n                    <div class="card-body">\n                        <h5 class="card-title">350</h5>\n                        <p class="card-text">Total items</p>\n                        <button class="btn btn-light">Quick Action</button>\n                    </div>\n                </div>\n            </div>\n        </div>\n    </div>\n    <script src="https://code.jquery.com/jquery-3.5.1.slim.min.js"></script>\n    <script src="https://cdn.jsdelivr.net/npm/@popperjs/core@2.0.7/dist/umd/popper.min.js"></script>\n    <script src="https://stackpath.bootstrapcdn.com/bootstrap/4.5.2/js/bootstrap.min.js"></script>\n</body>\n</html>